import Starling from '../src/base';
import { StarlingWebError } from '../src/error';
import { LocalStorage } from 'node-localstorage';
const request = jest.fn();

const storeInstance = new LocalStorage('./starling', 5 * 1024 * 1024);

const StarlingConfigs = {
  api_key: 'c71af3302f0b11eb813ce152e385e2d5',
  namespace: 'starling_client',
  locale: 'en',
  timeout: 8000,
  zoneHost: 'https://starling.snssdk.com',
  TEAChannelDomain: 'https://mcs.snssdk.com',
};

describe('集成测试 - Starling Client', () => {
  test('正常拉取 zh 文案', async () => {
    // 结构应当是 { starling: 'Starling' }
    const text = await new Starling(Object.assign({}, StarlingConfigs, { locale: 'zh' })).load();
    expect(text).toEqual(
      expect.objectContaining({
        starling: 'Starling',
      })
    );
  });

  test('正常拉取 zh 文案 超时error', async () => {
    // 结构应当是 { starling: 'Starling' }
    const text = await new Starling(
      Object.assign({}, StarlingConfigs, { locale: 'zh', timeout: 1 })
    )
      .load()
      .catch((e) => {
        expect(e.code).toEqual('ECONNABORTED');
      });
  });

  test('模拟 onerror', async () => {
    // 结构应当是 { starling: 'Starling' }
    const text = await new Starling(
      Object.assign({}, StarlingConfigs, {
        locale: 'zh',
        zoneHost: 'https://starling111.snssdk.com',
      })
    )
      .load()
      .catch((e) => {
        expect(e.message).toEqual('Network Error');
      });
  });

  test('正常拉取 en 文案', async () => {
    // 结构应当是 { starling: 'Starling', starling_1: 'starling_1 }
    const text = await new Starling(Object.assign({}, StarlingConfigs, { locale: 'en' })).load();

    expect(text).toEqual(
      expect.objectContaining({
        starling: 'Starling',
        starling_1: 'starling_1',
      })
    );
  });

  test('拉取不存在的 ko 文案', async () => {
    const text = await new Starling(Object.assign({}, StarlingConfigs, { locale: 'ko' })).load();
    expect(text).toEqual(expect.objectContaining({}));
  });

  test('拉取错误 api key 的 en 文案', async () => {
    return new Starling(
      Object.assign({}, StarlingConfigs, {
        locale: 'en',
        api_key: '123',
      })
    )
      .load()
      .then(
        (value) => {},
        (reason) => {
          // 没有缓存，结果应当是空对象
          expect(reason.response.data).toEqual(expect.objectContaining({}));
        }
      );
  });

  test('拉取错误 api key 的 zh 文案', async () => {
    return new Starling(
      Object.assign({}, StarlingConfigs, {
        locale: 'zh',
        api_key: '123',
      })
    )
      .load()
      .then(
        (value) => {},
        (reason) => {
          // 没有缓存，结果应当是空对象
          expect(reason.response.data).toEqual(expect.objectContaining({}));
        }
      );
  });

  test('拉取错误 namespace 的 en 文案', async () => {
    return new Starling(
      Object.assign({}, StarlingConfigs, {
        locale: 'en',
        namespace: 'wangqinhong',
      })
    )
      .load()
      .then(
        (value) => {
          // 空间错误，后端返回 {"message":{"Data":{},"Version":"0","Updated":true,"Lang":"en"},"status":200}
          // 所以 value 应当是空对象
          expect(value).toEqual(expect.objectContaining({}));
        },
        (reason) => {}
      );
  });

  test('拉取错误 namespace 的 zh 文案', async () => {
    return new Starling(
      Object.assign({}, StarlingConfigs, {
        locale: 'zh',
        namespace: 'wangqinhong',
      })
    )
      .load()
      .then(
        (value) => {
          // 空间错误，后端返回 {"message":{"Data":{},"Version":"0","Updated":true,"Lang":"zh"},"status":200}
          // 所以 value 应当是空对象
          expect(value).toEqual(expect.objectContaining({}));
        },
        (reason) => {}
      );
  });

  test('正常拉取 en 文案 cache false', async () => {
    request.mockReturnValue({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: { cache: 'true' }, Updated: true },
      },
    });
    const text = await new Starling(
      Object.assign({}, StarlingConfigs, {
        cache: false,
        locale: 'en',
        request,
        store: {
          get(key) {
            return {
              cache: 'false',
            };
          },
          set(key, value) {
            return storeInstance.setItem(key, JSON.stringify(value));
          },
        },
      })
    ).load();

    expect(text).toEqual({ cache: 'true' });
  });

  test('正常拉取 en 文案 cache true', async () => {
    request.mockReturnValue({
      data: {
        status: 200,
        message: { Version: '', Lang: '', Data: null, Updated: false },
      },
    });
    const text = await new Starling(
      Object.assign({}, StarlingConfigs, {
        cache: true,
        locale: 'en',
        request,
        store: {
          get(key) {
            return {
              cache: 'cache',
            };
          },
          set(key, value) {
            return storeInstance.setItem(key, JSON.stringify(value));
          },
        },
      })
    ).load();

    expect(text).toEqual({ cache: 'cache' });
  });
});

describe('LocalStorage 模拟', () => {
  beforeAll(() => {
    // 保存原本的 localStorage
    const originalLocalStorage = global.localStorage;

    // 创建一个不支持 localStorage 的模拟
    Object.defineProperty(global, 'localStorage', {
      value: {},
      configurable: true,
    });

    // 在测试完成后还原原本的 localStorage
    afterAll(() => {
      global.localStorage = originalLocalStorage;
    });
  });

  test('模拟 localStorage 不支持的情况', async () => {
    const text = await new Starling(
      Object.assign({}, StarlingConfigs, {
        locale: 'zh',
        zoneHost: 'https://starling111.snssdk.com',
      })
    )
      .load()
      .catch((e) => {
        expect(e.message).toEqual('Network Error');
      });
  });
});
